Using the OmniScalar type, you can define a field where the scalar type is nondeterministic.  For example, take this Elasticsearch term aggregation on the `_type` and `year` fields in the index:

```
{
  "_type": {
    "buckets": [
      {
        "key": "article",
        "doc_count": 367086
      },
      {
        "key": "video",
        "doc_count": 40046
      }
    ],
    "sum_other_doc_count": 0,
    "doc_count_error_upper_bound": 0
  },
  "year": {
    "buckets": [
      {
        "key": 2015,
        "doc_count": 2963
      },
      {
        "key": 2016,
        "doc_count": 2059
      }
    ],
    "sum_other_doc_count": 357862,
    "doc_count_error_upper_bound": 614
  }
}
```

The `key` field is either a `String` or an `Int` depending on how it was mapped in Elasticsearch.  We'd like to make the aggregations part of the GraphQL schema, so instead of requiring the developer to define a union of object types with varying scalars for the `key` field, we simplify the schema by declaring only `key = OmniScalar()`.

The data is about the minimal set that exercises all current features (and #484)

For brevity, it omits some "required" stuff we don't currently use, like the byProgramStructure tree, and the raw{Time,Flops} metrics.

@ioeric

- [x] update_identity (is)
- [x] get_schedule (sbm)
- [x] get_messageset (sbm)
- [x] get_subscriptions (sbm)
- [x] update_subscription (sbm)
- [ ] create_outbound (ms)

```
def patch_identity(identity, data):
    """ Patches the given identity with the data provided
    """
    url = "%s/%s/%s/" % (settings.IDENTITY_STORE_URL, "identities", identity)
    data = data
    headers = {
        'Authorization': 'Token %s' % settings.IDENTITY_STORE_TOKEN,
        'Content-Type': 'application/json'
    }
    r = requests.patch(url, data=json.dumps(data), headers=headers)
    r.raise_for_status()
    return r.json()
```

```
def get_schedule(schedule_id):
    url = "%s/%s/%s/" % (settings.STAGE_BASED_MESSAGING_URL,
                         "schedule", schedule_id)
    headers = {
        'Authorization': 'Token %s' % settings.STAGE_BASED_MESSAGING_TOKEN,
        'Content-Type': 'application/json'
    }
    r = requests.get(url, headers=headers)
    r.raise_for_status()
    return r.json()
```

```
def get_messageset(messageset_id):
    url = "%s/%s/%s/" % (settings.STAGE_BASED_MESSAGING_URL, "messageset",
                         messageset_id)
    headers = {
        'Authorization': 'Token %s' % settings.STAGE_BASED_MESSAGING_TOKEN,
        'Content-Type': 'application/json'
    }
    r = requests.get(url, headers=headers)
    r.raise_for_status()
    return r.json()
```

```
def get_subscriptions(params):
    url = "%s/%s/" % (settings.STAGE_BASED_MESSAGING_URL, "subscriptions")
    headers = {
        'Authorization': 'Token %s' % settings.STAGE_BASED_MESSAGING_TOKEN,
        'Content-Type': 'application/json'
    }
    r = requests.get(url, params=params, headers=headers)
    r.raise_for_status()
    return r.json()
```

```
def patch_subscription(subscription_id, data):
    """ Patches the given subscription with the data provided
    """
    url = "%s/%s/%s/" % (settings.STAGE_BASED_MESSAGING_URL,
                         "subscriptions", subscription_id)
    data = data
    headers = {
        'Authorization': 'Token %s' % settings.STAGE_BASED_MESSAGING_TOKEN,
        'Content-Type': 'application/json'
    }
    r = requests.patch(url, data=json.dumps(data), headers=headers)
    r.raise_for_status()
    return r.json()
```

```
def post_message(payload):
    result = requests.post(
        url="%s/outbound/" % settings.MESSAGE_SENDER_URL,
        data=json.dumps(payload),
        headers={
            'Content-Type': 'application/json',
            'Authorization': 'Token %s' % settings.MESSAGE_SENDER_TOKEN
        }
    )
    result.raise_for_status()
    return result.json()
```

